    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTicker
        //
        //     {
        //         "market":"ETH-BTC",
        //         "open":"0.022578",
        //         "high":"0.023019",
        //         "low":"0.022573",
        //         "last":"0.023019",
        //         "volume":"25.16366324",
        //         "volumeQuote":"0.57333305",
        //         "bid":"0.023039",
        //         "bidSize":"0.53500578",
        //         "ask":"0.023041",
        //         "askSize":"0.47859202",
        //         "timestamp":1590381666900
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "market");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object timestamp = this.safeInteger(ticker, "timestamp");
        Object last = this.safeString(ticker, "last");
        Object baseVolume = this.safeString(ticker, "volume");
        Object quoteVolume = this.safeString(ticker, "volumeQuote");
        Object open = this.safeString(ticker, "open");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitvavoCore.this.iso8601(timestamp) );
            put( "high", BitvavoCore.this.safeString(ticker, "high") );
            put( "low", BitvavoCore.this.safeString(ticker, "low") );
            put( "bid", BitvavoCore.this.safeString(ticker, "bid") );
            put( "bidVolume", BitvavoCore.this.safeString(ticker, "bidSize") );
            put( "ask", BitvavoCore.this.safeString(ticker, "ask") );
            put( "askVolume", BitvavoCore.this.safeString(ticker, "askSize") );
            put( "vwap", null );
            put( "open", open );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

