    /**
     * @method
     * @name bitvavo#fetchTrades
     * @see https://docs.bitvavo.com/docs/rest-api/get-trades/
     * @description get the list of most recent trades for a particular symbol
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch entries for
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchTrades", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDynamic("fetchTrades", symbol, since, limit, parameters)).join();
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", Helpers.mathMin(limit, 1000));
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start", since);
            }
            var requestparametersVariable = this.handleUntilOption("end", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = (this.publicGetMarketTrades(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "id":"94154c98-6e8b-4e33-92a8-74e33fc05650",
            //             "timestamp":1590382761859,
            //             "amount":"0.06026079",
            //             "price":"8095.3",
            //             "side":"buy"
            //         }
            //     ]
            //
            return this.parseTrades(response, market, since, limit);
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "id":"94154c98-6e8b-4e33-92a8-74e33fc05650",
        //         "timestamp":1590382761859,
        //         "amount":"0.06026079",
        //         "price":"8095.3",
        //         "side":"buy"
        //     }
        //
        // createOrder, fetchOpenOrders, fetchOrders, editOrder (private)
        //
        //     {
        //         "id":"b0c86aa5-6ed3-4a2d-ba3a-be9a964220f4",
        //         "timestamp":1590505649245,
        //         "amount":"0.249825",
        //         "price":"183.49",
        //         "taker":true,
        //         "fee":"0.12038925",
        //         "feeCurrency":"EUR",
        //         "settled":true
        //     }
        //
        // fetchMyTrades (private)
        //
        //     {
        //         "id":"b0c86aa5-6ed3-4a2d-ba3a-be9a964220f4",
        //         "orderId":"af76d6ce-9f7c-4006-b715-bb5d430652d0",
        //         "timestamp":1590505649245,
        //         "market":"ETH-EUR",
        //         "side":"sell",
        //         "amount":"0.249825",
        //         "price":"183.49",
        //         "taker":true,
        //         "fee":"0.12038925",
        //         "feeCurrency":"EUR",
        //         "settled":true
        //     }
        //
        // watchMyTrades (private)
        //
        //     {
        //         "event": "fill",
        //         "timestamp": 1590964470132,
        //         "market": "ETH-EUR",
        //         "orderId": "85d082e1-eda4-4209-9580-248281a29a9a",
        //         "fillId": "861d2da5-aa93-475c-8d9a-dce431bd4211",
        //         "side": "sell",
        //         "amount": "0.1",
        //         "price": "211.46",
        //         "taker": true,
        //         "fee": "0.056",
        //         "feeCurrency": "EUR"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "amount");
        Object timestamp = this.safeInteger(trade, "timestamp");
        Object side = this.safeString(trade, "side");
        Object id = this.safeString2(trade, "id", "fillId");
        Object marketId = this.safeString(trade, "market");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object taker = this.safeValue(trade, "taker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(taker, null)))
        {
            takerOrMaker = ((Helpers.isTrue(taker))) ? "taker" : "maker";
        }
        Object feeCostString = this.safeString(trade, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "feeCurrency");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        Object orderId = this.safeString(trade, "orderId");
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitvavoCore.this.iso8601(timestamp) );
            put( "order", orderId );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

